package com.parfyonoff.webscraper.file.writer;import com.fasterxml.jackson.core.exc.StreamWriteException;import com.fasterxml.jackson.core.type.TypeReference;import com.fasterxml.jackson.databind.DatabindException;import com.fasterxml.jackson.databind.ObjectMapper;import com.fasterxml.jackson.databind.ObjectWriter;import com.parfyonoff.webscraper.agregation.AggregatedData;import com.parfyonoff.webscraper.file.FileException;import java.io.File;import java.io.IOException;import java.util.ArrayList;import java.util.List;public class JsonWriter {    private final static ObjectMapper objectMapper = new ObjectMapper();    private final static ObjectWriter objectWriter = objectMapper.writerWithDefaultPrettyPrinter();    public static void write(File file, AggregatedData aggregatedData) {        try {            objectWriter.writeValue(file, List.of(aggregatedData));        } catch (StreamWriteException exc) {            throw new FileException("Can't write data to json file: " + exc.getMessage());        } catch (DatabindException exc) {            throw new FileException("Can't bind data: " + exc.getMessage());        } catch (IOException exc) {            throw new FileException("Unexpected IO exception while writing to json file: " + exc.getMessage());        }    }    public static void append(File file, AggregatedData aggregatedData) {        try {            List<AggregatedData> aggregatedDataList;            if (!file.exists()) {                aggregatedDataList = new ArrayList<>();            } else {                aggregatedDataList = objectMapper.readValue(file, new TypeReference<List<AggregatedData>>() {                });            }            aggregatedDataList.add(aggregatedData);            objectWriter.writeValue(file, aggregatedDataList);        } catch (StreamWriteException exc) {            throw new FileException("Can't append data to json file: " + exc.getMessage());        } catch (DatabindException exc) {            throw new FileException("Can't bind data: " + exc.getMessage());        } catch (IOException exc) {            throw new FileException("Unexpected IO exception while appending to json file: " + exc.getMessage());        }    }}